+/**
+ * Tiny 5x5 ASCII letter renderer.
+ *
+ * Each glyph is a 5-row array of strings. `#` marks a filled cell, ` ` an empty one.
+ * Unknown characters fall back to a blank glyph so the renderer never throws.
+ */
+
+/** @type {Record<string, string[]>} */
+const glyphs = {
+	A: [' ### ', '#   #', '#####', '#   #', '#   #'],
+	B: ['#### ', '#   #', '#### ', '#   #', '#### '],
+	C: [' ####', '#    ', '#    ', '#    ', ' ####'],
+	D: ['#### ', '#   #', '#   #', '#   #', '#### '],
+	E: ['#####', '#    ', '###  ', '#    ', '#####'],
+	F: ['#####', '#    ', '###  ', '#    ', '#    '],
+	I: ['#####', '  #  ', '  #  ', '  #  ', '#####'],
+	L: ['#    ', '#    ', '#    ', '#    ', '#####'],
+	M: ['#   #', '## ##', '# # #', '#   #', '#   #'],
+	T: ['#####', '  #  ', '  #  ', '  #  ', '  #  '],
+	' ': ['     ', '     ', '     ', '     ', '     '],
+};
+
+const BLANK = glyphs[' '];
+
+/**
+ * Render a string as a multi-line ASCII banner.
+ *
+ * @param {string} text - text to render. Case-insensitive; unsupported chars become blanks.
+ * @returns {string} the rendered banner ready to be printed.
+ */
+export function render_banner(text) {
+	const chars = text.toUpperCase().split('');
+	const rows = ['', '', '', '', ''];
+	for (const char of chars) {
+		const glyph = glyphs[char] ?? BLANK;
+		for (let i = 0; i < 5; i++) {
+			rows[i] += glyph[i] + ' ';
+		}
+	}
+	return rows.join('\n');
+}

