+/**
+ * Frame-based terminal animation primitives.
+ *
+ * No external deps: we just write escape sequences directly to stdout.
+ */
+
+const CLEAR_SCREEN = '\x1b[2J';
+const MOVE_HOME = '\x1b[H';
+const HIDE_CURSOR = '\x1b[?25l';
+const SHOW_CURSOR = '\x1b[?25h';
+
+/**
+ * @param {number} ms
+ * @returns {Promise<void>}
+ */
+const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
+
+/**
+ * Play a list of frames sequentially in the current terminal.
+ *
+ * The screen is cleared between frames so each frame fully replaces the previous one.
+ * The cursor is hidden during playback and restored once finished (including on errors).
+ *
+ * @param {string[]} frames - rendered frames, already colorized if desired.
+ * @param {{ fps?: number, loops?: number }} [options]
+ * @returns {Promise<void>}
+ */
+export async function play(frames, options = {}) {
+	const fps = options.fps ?? 8;
+	const loops = options.loops ?? 1;
+	const delay = Math.max(1, Math.round(1000 / fps));
+
+	process.stdout.write(HIDE_CURSOR);
+	try {
+		for (let loop = 0; loop < loops; loop++) {
+			for (const frame of frames) {
+				process.stdout.write(CLEAR_SCREEN + MOVE_HOME + frame);
+				await sleep(delay);
+			}
+		}
+	} finally {
+		process.stdout.write(SHOW_CURSOR + '\n');
+	}
+}
+
+/**
+ * Generate a "marquee" of frames by sliding `text` across a window of `width` columns.
+ *
+ * The text is padded with spaces on both sides so it scrolls in from the right and
+ * disappears on the left, producing a classic ticker-tape effect.
+ *
+ * @param {string} text
+ * @param {number} width - visible window width in characters.
+ * @returns {string[]} array of frames suitable for `play`.
+ */
+export function marquee(text, width) {
+	const padded = ' '.repeat(width) + text + ' '.repeat(width);
+	const frames = [];
+	for (let i = 0; i <= padded.length - width; i++) {
+		frames.push(padded.slice(i, i + width));
+	}
+	return frames;
+}

