+#!/usr/bin/env node
+/**
+ * Tiny demo CLI tying the playground modules together.
+ *
+ * Usage:
+ *   node src/playground/demo.js              -> renders a rainbow "LETMEDIFF" banner
+ *   node src/playground/demo.js --animate    -> scrolls the banner as a marquee
+ *   node src/playground/demo.js "HELLO"      -> renders a custom word
+ */
+
+import { render_banner } from './banner.js';
+import { rainbow } from './colors.js';
+import { marquee, play } from './animate.js';
+
+/**
+ * Parse positional + flag args without pulling in a dependency.
+ *
+ * @param {string[]} argv
+ * @returns {{ text: string, animate: boolean }}
+ */
+function parse_args(argv) {
+	const args = argv.slice(2);
+	const animate = args.includes('--animate');
+	const text = args.find((arg) => !arg.startsWith('--')) ?? 'LETMEDIFF';
+	return { text, animate };
+}
+
+async function main() {
+	const { text, animate } = parse_args(process.argv);
+	const banner = render_banner(text);
+
+	if (!animate) {
+		console.log(rainbow(banner));
+		return;
+	}
+
+	const rows = banner.split('\n');
+	const width = 40;
+	const frame_rows = rows.map((row) => marquee(row, width));
+	const frame_count = frame_rows[0].length;
+
+	const frames = [];
+	for (let i = 0; i < frame_count; i++) {
+		const composed = frame_rows.map((row_frames) => row_frames[i]).join('\n');
+		frames.push(rainbow(composed));
+	}
+
+	await play(frames, { fps: 24, loops: 2 });
+}
+
+main().catch((error) => {
+	console.error(error);
+	process.exit(1);
+});
